Here's the XAML and ViewModel for your requirements:

### XAML

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="Auto,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1"
                           Text="{Binding Name}"
                           VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>
</RefreshView>
```

### ViewModel

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool isRefreshing;

    [ObservableProperty]
    private Item? currentItem;

    public ObservableCollection<Item> Items { get; } = new();

    [RelayCommand]
    private async Task RefreshAsync()
    {
        var data = await _api.GetItemsAsync();
        MainThread.BeginInvokeOnMainThread(() =>
        {
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        });
        IsRefreshing = false;   // tells RefreshView to stop the spinner
    }

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;
        await _nav.GoToAsync("DetailPage", new() { ["Item"] = CurrentItem });
        CurrentItem = null;     // reset so the same item can be re-selected
    }
}
```

### Key binding points

| XAML property | ViewModel property | Notes |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool, TwoWay) | Set `false` when load completes |
| `RefreshView.Command` | `RefreshCommand` | Calls your API, repopulates `Items` |
| `CollectionView.SelectedItem` | `CurrentItem` (TwoWay) | Holds the tapped item |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Navigates, then nulls `CurrentItem` |
| `CollectionView.ItemsSource` | `Items` (`ObservableCollection<T>`) | Must be `ObservableCollection`, not `List` |

**Important details:**
- Always set `IsRefreshing = false` after loading — otherwise the spinner never stops.
- Reset `CurrentItem = null` after navigation so the same row can be selected again.
- Use `x:DataType` on `DataTemplate` for compiled bindings.
- Update the collection on the **UI thread** via `MainThread.BeginInvokeOnMainThread`.
